from itertools import groupby
class Solution:
    def car_race_collision(self, cars: List[str], target: str) -> str:
        directions = {
            "N": 1,
            "S": -1,
            'E': 1,
                'W': -1
        }
        positions = []
        for car, pos in groupby(cars):
            if car == target:
                break
            count = 0
            for c in pos:
                count += directions[c]
            positions.append(count)
        return 'S' if positions[0] < positions[-1] else 'N' if positions[-1]<0 else 'E' if positions [-1]> positions[0]
